import { useState } from "react";

function App() {

  const [func, setFunc] = useState('x**2');
  const [limitA, setLimitA] = useState('1');
  const [limitB, setLimitB] = useState('10');
  const [num, setNum] = useState('10');

  function leftRec(f, a, b, n) {
    let h = (b - a) / n;
    let x = +a;
    let y = 0;

    for (let i = 0; i < n; i++) {
      y += eval(f);
      console.log(eval(f) + ' и ' + x);
      x += h;
    }

    console.log(y + " * h");

    return h * y;
  }

  let sum = leftRec(func, limitA, limitB, num);

  return (
    <div className="wrapper">
      <header>
        <h3>КАЛЬКУЛЯТОР</h3>
        <p>Приближённое вычисление определённых интегралов</p>
      </header>

      <div className="content">
        

        <form>

          <select id="method">
            <option value={1}>Левых прямоугольников</option>
            <option value={2}>Правых прямоугольников</option>
          </select>

          <div className="func">
            <p>f(x) =</p>
            <input 
              type="text" 
              required
              value={func} 
              onChange={(e) => setFunc(e.target.value)}
            />
          </div>

          <div className="limit">
            <div className="limit-a">
              <p>a =</p>
              <input 
                type="number" 
                required
                value={limitA}
                onChange={(e) => setLimitA(e.target.value)}
              />
            </div>

            <div className="limit-b">
              <p>b =</p>
              <input 
                type="number" 
                required
                value={limitB}
                onChange={(e) => setLimitB(e.target.value)} 
              />
            </div>
          </div>

          <div className="num">
            <p>n =</p>
            <input 
              type="number"
              required 
              value={num}
              onChange={(e) => setNum(e.target.value)} 
            />
          </div>

          {/* <div className="float">
            <p>Знаков после запятой:</p>
            <div className="slider">
              <input type="range" min="0" max="10" defaultValue= "3"/>
              <span className="number">3</span>
            </div>
          </div> */}

          <p>{ func }</p>
          <p>{ limitA }</p>
          <p>{ limitB }</p>
          <p>{ num }</p>
          <p>{ func }</p>
          <p>{ sum }</p>

        </form>

      </div>

    </div>
  );
}

export default App;